1	export type Customer = { yearsWithMHPCO: number };
2	export type Item = {
3	  type: string;
4	  material?: string;
5	  enchantment?: number;
6	  cursed?: boolean;
7	};
8	export type Damage = { itemType: string; amount: number };
9	export type Incident = { cause: string; damages: Damage[] };
10	export type QuoteStep = { op: "quote"; items: Item[] };
11	export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
12	export type Step = QuoteStep | ClaimStep;
13	export type Scenario = { customer: Customer; steps: Step[] };
14	export type QuoteResult = { premium: number };
15	export type ClaimResult = { payout: number; remainingCap: number };
16	export type ScenarioResult = { results: (QuoteResult | ClaimResult)[] };
17	
18	const PROCESSING_FEE = 5;
19	const FIRST_INSURANCE_RATE = 0.1;
20	
21	const BASE_PREMIUMS: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	  moonstone: 25,
28	};
29	
30	const baseFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
31	
32	const BLOCK_OF_3_PREMIUM = 60;
33	
34	const runeBasePremium = (runeCount: number): number =>
35	  runeCount === 3 ? BLOCK_OF_3_PREMIUM : runeCount * baseFor({ type: "rune" });
36	
37	const sumBasePremiums = (items: Item[]): number => {
38	  const runeCount = items.filter((i) => i.type === "rune").length;
39	  const nonRunes = items.filter((i) => i.type !== "rune");
40	  const nonRunesBase = nonRunes.reduce((sum, item) => sum + baseFor(item), 0);
41	  return runeBasePremium(runeCount) + nonRunesBase;
42	};
43	
44	const quotePremium = (items: Item[]): number => {
45	  const itemsBase = sumBasePremiums(items);
46	  const firstInsurance = itemsBase * FIRST_INSURANCE_RATE;
47	  return Math.ceil(itemsBase + firstInsurance + PROCESSING_FEE);
48	};
49	
50	export const runScenario = (scenario: Scenario): ScenarioResult => {
51	  const results = scenario.steps.map((step) => {
52	    if (step.op === "quote") return { premium: quotePremium(step.items) };
53	    return { payout: 0, remainingCap: 0 };
54	  });
55	  return { results };
56	};
